// Application layer — a Use Case exposed 1:1 as a Skill. Atomic and typed.
import type { RepositoryPort, EventBusPort } from './ports'
import type { EntityId } from '../domain/entity'

export interface UseCaseInput { id: EntityId }
export interface UseCaseOutput { ok: boolean }

export class ExampleUseCase {
  constructor(
    private readonly repo: RepositoryPort,
    private readonly bus: EventBusPort,
  ) {}

  // Side effects only via injected connectors — never direct infra access.
  async execute(input: UseCaseInput): Promise<UseCaseOutput> {
    const entity = await this.repo.findById(input.id)
    if (!entity) return { ok: false }
    await this.bus.publish({ name: 'example.done', occurredAt: new Date().toISOString(), payload: { id: input.id } })
    return { ok: true }
  }
}

