// Secure Key Broker — the ONLY place secrets are resolved (R19).
// No other layer may call process.env or read raw config files.
export interface SecretRequest { keyId: string; scope: string }

export interface SecureKeyBroker {
  resolve(req: SecretRequest): Promise<string>
}

// Single runtime injection point. Implementation reads from the gitignored
// secret store (services.private.json) — never logs or serializes secrets.
export function createSecureKeyBroker(
  store: Readonly<Record<string, string>>,
): SecureKeyBroker {
  return {
    async resolve({ keyId }: SecretRequest): Promise<string> {
      const value = store[keyId]
      if (!value) throw new Error(`Secret not found: ${keyId}`)
      return value
    },
  }
}

