// Skill = atomic, typed, reusable entry point mapped 1:1 to a use case.
// Wires the use case with injected connectors (composition root per domain).
import { ExampleUseCase, type UseCaseInput, type UseCaseOutput } from '../application/use-case'
import { createRepositoryAdapter } from '../infrastructure/repository.adapter'
import { createSecureKeyBroker } from '../infrastructure/secure-key-broker'

export async function exampleSkill(
  input: UseCaseInput,
  secretStore: Readonly<Record<string, string>>,
  bus: import('../application/ports').EventBusPort,
): Promise<UseCaseOutput> {
  const broker = createSecureKeyBroker(secretStore)
  const repo = createRepositoryAdapter(broker)
  return new ExampleUseCase(repo, bus).execute(input)
}
